package com.pqc.core.entity;
import jakarta.persistence.*; import lombok.*; import java.time.LocalDateTime;
@Entity @Table(name="marketing_campaigns") @Data @Builder @NoArgsConstructor @AllArgsConstructor public class MarketingCampaign {@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false) private String name; @Column(length=2000) private String description; @Enumerated(EnumType.STRING) @Column(nullable=false) private CampaignType campaignType; @Column(nullable=false) private String targetSegment; @Builder.Default @Enumerated(EnumType.STRING) @Column(nullable=false) private CampaignStatus status=CampaignStatus.DRAFT; private LocalDateTime startsAt; private LocalDateTime endsAt; private LocalDateTime createdAt; private LocalDateTime updatedAt; @PrePersist void create(){createdAt=updatedAt=LocalDateTime.now();} @PreUpdate void update(){updatedAt=LocalDateTime.now();}}
